VALUES
  ('fire-eq-tech-moex-03300', 'fire-eq-tech', 'fire-eq-tech-moex-097-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '下列有關燃燒範圍的敘述，何者錯誤？', '["燃燒範圍會隨壓力或溫度不同而變化", "利用二氧化碳滅火的原理，係在改變起火物質的燃燒範圍", "燃燒範圍是指可燃性氣體與空氣的混合比例達可能燃燒之濃度範圍", "可燃性混合氣體的燃燒下限愈低，危險性愈高"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "75a2171b794e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03301', 'fire-eq-tech', 'fire-eq-tech-moex-097-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '下列不同重量之燃料燃燒時，何者之理論空氣量最小？', '["28公斤的一氧化碳（CO）", "32公斤的硫", "4公斤的氫氣（H ）", "12公斤的碳 2"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "75a2171b794e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03302', 'fire-eq-tech', 'fire-eq-tech-moex-097-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '影響粉塵爆炸的因素，下列何者正確？', '["粉塵的化學組成，與爆炸無關", "處理乾燥粉塵，無須特別注意", "粉塵中含微小粒子愈多者，爆炸可能性愈高", "無所謂爆炸界限"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "75a2171b794e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03303', 'fire-eq-tech', 'fire-eq-tech-moex-097-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '引火點在100℃以下的物質，下列敘述何者不正確？', '["有良好流動性", "引火點與燃燒點極為接近", "若滲入多孔質的布料中，極容易引火", "處於流動狀態者較處於靜止狀態者更容易著火"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "75a2171b794e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03304', 'fire-eq-tech', 'fire-eq-tech-moex-097-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '對於準自然發火物質「金屬鈉」的敘述，下列何者錯誤？', '["與水接觸立即起火，故又稱禁水性物質", "依我國危險物品的分類，是第二類物質", "常用於原子爐的冷卻機，有機溶劑中微量水分的脫水劑", "燃燒時發生過氧化鈉與氫氧化鈉的白煙"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "75a2171b794e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03305', 'fire-eq-tech', 'fire-eq-tech-moex-097-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '對於引火與發火的區別，下列敘述何者正確？', '["自可燃物產生蒸氣時，由火焰能引燃的最低溫稱為發火點", "可燃物受熱時不藉火焰或電氣火花點火時，也能自燃的現象稱為引火", "若利用加熱包間接加熱至被加熱物本身起燃所需最低溫稱為發火點", "發火點通常較引火點為低"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "75a2171b794e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03306', 'fire-eq-tech', 'fire-eq-tech-moex-097-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '關於火災中生成的CO與CO 對人體的危害情形，下列敘述何者錯誤？ 2', '["CO 本身沒有毒性，但過量吸入時，會引起呼吸困難 2", "CO是火災中最常發生的毒氣，且為血液毒", "CO常會阻礙紅血球的輸氧功能", "當空間中的CO 濃度達到1%時，在短時間內就會造成人體窒息死亡 2"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "75a2171b794e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03307', 'fire-eq-tech', 'fire-eq-tech-moex-097-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '在密閉空間注入不燃性氣體，造成氧氣之濃度降低，進而使燃燒無法持續而滅火，此方法屬下列何種滅火方法？', '["冷卻法", "窒息法", "移除法", "抑制法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "75a2171b794e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03308', 'fire-eq-tech', 'fire-eq-tech-moex-097-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '不飽和油脂自然發火之危險性，通常可用碘價（Iodine-value）判斷之。凡碘價超過多少以上者，可視為危險？', '["100", "130", "160", "190"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "75a2171b794e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03309', 'fire-eq-tech', 'fire-eq-tech-moex-097-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '下列何種物質具不燃性？', '["硫化氫（H S）", "苯（C H ）", "四氯化碳（CCl ）", "丙烷（C H ）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "75a2171b794e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
